contracts/core/AIModerationContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title AIModerationContract
 * @notice Manages AI moderation decisions, human review, and appeals
 * @dev Stores moderation results and tracks AI performance metrics
 */
contract AIModerationContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant AI_SERVICE_ROLE = keccak256("AI_SERVICE_ROLE");
    bytes32 public constant MODERATOR_ROLE = keccak256("MODERATOR_ROLE");

    enum ModerationDecision {
        Pending,
        Approved,
        Rejected,
        Flagged,
        UnderReview
    }

    enum AppealStatus {
        None,
        Pending,
        Approved,
        Rejected
    }

    struct ModerationResult {
        uint256 contentId;
        address author;
        uint8 toxicityScore;      // 0-100
        uint8 sentimentScore;     // 0-100
        uint8 constructivenessScore; // 0-100
        uint8 spamScore;          // 0-100
        ModerationDecision decision;
        uint256 timestamp;
        string rejectionReason;
        bool requiresHumanReview;
    }

    struct Appeal {
        uint256 contentId;
        address appellant;
        string justification;
        uint256 appealTime;
        AppealStatus status;
        address reviewer;
        uint256 reviewTime;
        string reviewNotes;
    }

    struct ModerationStats {
        uint256 totalModerated;
        uint256 approved;
        uint256 rejected;
        uint256 flagged;
        uint256 appealsSubmitted;
        uint256 appealsApproved;
    }

    // Moderation thresholds
    uint8 public toxicityThreshold = 70;
    uint8 public spamThreshold = 80;
    uint8 public constructivenessMinimum = 30;

    // Mappings
    mapping(uint256 => ModerationResult) public moderationResults;
    mapping(uint256 => Appeal) public appeals;
    mapping(address => uint256[]) public userContent;
    mapping(address => ModerationStats) public userStats;
    
    ModerationStats public globalStats;
    
    uint256 public totalContentModerated;
    uint256[] public flaggedContent;

    // Events
    event ContentModerated(
        uint256 indexed contentId,
        address indexed author,
        ModerationDecision decision,
        uint8 toxicityScore,
        uint8 constructivenessScore,
        uint256 timestamp
    );
    event ContentFlagged(uint256 indexed contentId, string reason, uint256 timestamp);
    event AppealSubmitted(uint256 indexed contentId, address indexed appellant, uint256 timestamp);
    event AppealReviewed(
        uint256 indexed contentId,
        AppealStatus status,
        address indexed reviewer,
        uint256 timestamp
    );
    event ThresholdsUpdated(
        uint8 toxicity,
        uint8 spam,
        uint8 constructiveness,
        uint256 timestamp
    );
    event HumanReviewCompleted(
        uint256 indexed contentId,
        ModerationDecision finalDecision,
        uint256 timestamp
    );

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    /**
     * @notice Record AI moderation decision
     * @param contentId ID of the content
     * @param author Address of content author
     * @param toxicity Toxicity score (0-100)
     * @param sentiment Sentiment score (0-100)
     * @param constructiveness Constructiveness score (0-100)
     * @param spam Spam score (0-100)
     */
    function recordModerationDecision(
        uint256 contentId,
        address author,
        uint8 toxicity,
        uint8 sentiment,
        uint8 constructiveness,
        uint8 spam
    ) external onlyRole(AI_SERVICE_ROLE) {
        require(moderationResults[contentId].timestamp == 0, "Already moderated");
        require(toxicity <= 100 && sentiment <= 100 && 
                constructiveness <= 100 && spam <= 100, "Invalid scores");

        ModerationDecision decision = _determineDecision(
            toxicity,
            spam,
            constructiveness
        );

        bool needsReview = _needsHumanReview(toxicity, spam, constructiveness);

        moderationResults[contentId] = ModerationResult({
            contentId: contentId,
            author: author,
            toxicityScore: toxicity,
            sentimentScore: sentiment,
            constructivenessScore: constructiveness,
            spamScore: spam,
            decision: needsReview ? ModerationDecision.Flagged : decision,
            timestamp: block.timestamp,
            rejectionReason: _getRejectionReason(toxicity, spam, constructiveness),
            requiresHumanReview: needsReview
        });

        userContent[author].push(contentId);
        totalContentModerated++;
        globalStats.totalModerated++;

        _updateStats(decision, author);

        if (needsReview) {
            flaggedContent.push(contentId);
            emit ContentFlagged(contentId, "AI flagged for review", block.timestamp);
        }

        emit ContentModerated(
            contentId,
            author,
            decision,
            toxicity,
            constructiveness,
            block.timestamp
        );
    }

    /**
     * @notice Determine moderation decision based on scores
     */
    function _determineDecision(
        uint8 toxicity,
        uint8 spam,
        uint8 constructiveness
    ) internal view returns (ModerationDecision) {
        if (toxicity > toxicityThreshold || spam > spamThreshold) {
            return ModerationDecision.Rejected;
        }
        
        if (constructiveness < constructivenessMinimum) {
            return ModerationDecision.Flagged;
        }

        return ModerationDecision.Approved;
    }

    /**
     * @notice Check if content needs human review
     */
    function _needsHumanReview(
        uint8 toxicity,
        uint8 spam,
        uint8 constructiveness
    ) internal view returns (bool) {
        // Borderline cases need human review
        uint8 toxicityMargin = 10;
        uint8 spamMargin = 10;
        uint8 constructivenessMargin = 10;

        bool borderlineToxicity = toxicity >= (toxicityThreshold - toxicityMargin) && 
                                  toxicity <= (toxicityThreshold + toxicityMargin);
        bool borderlineSpam = spam >= (spamThreshold - spamMargin) && 
                             spam <= (spamThreshold + spamMargin);
        bool borderlineConstructiveness = constructiveness >= (constructivenessMinimum - constructivenessMargin) && 
                                         constructiveness <= (constructivenessMinimum + constructivenessMargin);

        return borderlineToxicity || borderlineSpam || borderlineConstructiveness;
    }

    /**
     * @notice Get rejection reason based on scores
     */
    function _getRejectionReason(
        uint8 toxicity,
        uint8 spam,
        uint8 constructiveness
    ) internal view returns (string memory) {
        if (toxicity > toxicityThreshold) {
            return "High toxicity detected";
        }
        if (spam > spamThreshold) {
            return "Spam content detected";
        }
        if (constructiveness < constructivenessMinimum) {
            return "Low constructiveness score";
        }
        return "";
    }

    /**
     * @notice Update statistics
     */
    function _updateStats(ModerationDecision decision, address author) internal {
        if (decision == ModerationDecision.Approved) {
            globalStats.approved++;
            userStats[author].approved++;
        } else if (decision == ModerationDecision.Rejected) {
            globalStats.rejected++;
            userStats[author].rejected++;
        } else if (decision == ModerationDecision.Flagged) {
            globalStats.flagged++;
            userStats[author].flagged++;
        }
    }

    /**
     * @notice Submit appeal for rejected content
     * @param contentId ID of the content
     * @param justification Reason for appeal
     */
    function submitAppeal(uint256 contentId, string memory justification) external {
        ModerationResult memory result = moderationResults[contentId];
        require(result.timestamp > 0, "Content not moderated");
        require(result.author == msg.sender, "Not content author");
        require(result.decision == ModerationDecision.Rejected || 
                result.decision == ModerationDecision.Flagged, 
                "Content not rejected");
        require(appeals[contentId].appealTime == 0, "Appeal already submitted");
        require(bytes(justification).length > 0, "Justification required");

        appeals[contentId] = Appeal({
            contentId: contentId,
            appellant: msg.sender,
            justification: justification,
            appealTime: block.timestamp,
            status: AppealStatus.Pending,
            reviewer: address(0),
            reviewTime: 0,
            reviewNotes: ""
        });

        globalStats.appealsSubmitted++;
        userStats[msg.sender].appealsSubmitted++;

        emit AppealSubmitted(contentId, msg.sender, block.timestamp);
    }

    /**
     * @notice Review appeal (moderator only)
     * @param contentId ID of the content
     * @param approved Whether to approve the appeal
     * @param notes Review notes
     */
    function reviewAppeal(
        uint256 contentId,
        bool approved,
        string memory notes
    ) external onlyRole(MODERATOR_ROLE) {
        Appeal storage appeal = appeals[contentId];
        require(appeal.status == AppealStatus.Pending, "Appeal not pending");

        appeal.status = approved ? AppealStatus.Approved : AppealStatus.Rejected;
        appeal.reviewer = msg.sender;
        appeal.reviewTime = block.timestamp;
        appeal.reviewNotes = notes;

        if (approved) {
            moderationResults[contentId].decision = ModerationDecision.Approved;
            globalStats.appealsApproved++;
            userStats[appeal.appellant].appealsApproved++;
        }

        emit AppealReviewed(contentId, appeal.status, msg.sender, block.timestamp);
    }

    /**
     * @notice Complete human review for flagged content
     * @param contentId ID of the content
     * @param finalDecision Final moderation decision
     * @param notes Review notes
     */
    function completeHumanReview(
        uint256 contentId,
        ModerationDecision finalDecision,
        string memory notes
    ) external onlyRole(MODERATOR_ROLE) {
        ModerationResult storage result = moderationResults[contentId];
        require(result.requiresHumanReview, "Not flagged for review");
        require(result.decision == ModerationDecision.Flagged || 
                result.decision == ModerationDecision.UnderReview, 
                "Not under review");

        result.decision = finalDecision;
        result.requiresHumanReview = false;
        result.rejectionReason = notes;

        emit HumanReviewCompleted(contentId, finalDecision, block.timestamp);
    }

    /**
     * @notice Update moderation thresholds
     * @param toxicity New toxicity threshold
     * @param spam New spam threshold
     * @param constructiveness New constructiveness minimum
     */
    function updateThresholds(
        uint8 toxicity,
        uint8 spam,
        uint8 constructiveness
    ) external onlyRole(ADMIN_ROLE) {
        require(toxicity <= 100 && spam <= 100 && constructiveness <= 100, 
                "Invalid thresholds");

        toxicityThreshold = toxicity;
        spamThreshold = spam;
        constructivenessMinimum = constructiveness;

        emit ThresholdsUpdated(toxicity, spam, constructiveness, block.timestamp);
    }

    /**
     * @notice Get moderation result
     * @param contentId ID of the content
     * @return Moderation result struct
     */
    function getModerationResult(uint256 contentId) 
        external 
        view 
        returns (ModerationResult memory) 
    {
        return moderationResults[contentId];
    }

    /**
     * @notice Get appeal details
     * @param contentId ID of the content
     * @return Appeal struct
     */
    function getAppeal(uint256 contentId) external view returns (Appeal memory) {
        return appeals[contentId];
    }

    /**
     * @notice Get user's content IDs
     * @param user Address of the user
     * @return Array of content IDs
     */
    function getUserContent(address user) external view returns (uint256[] memory) {
        return userContent[user];
    }

    /**
     * @notice Get flagged content IDs
     * @return Array of flagged content IDs
     */
    function getFlaggedContent() external view returns (uint256[] memory) {
        return flaggedContent;
    }

    /**
     * @notice Get user statistics
     * @param user Address of the user
     * @return User moderation stats
     */
    function getUserStats(address user) external view returns (ModerationStats memory) {
        return userStats[user];
    }

    /**
     * @notice Get global statistics
     * @return Global moderation stats
     */
    function getGlobalStats() external view returns (ModerationStats memory) {
        return globalStats;
    }

    /**
     * @notice Grant AI service role
     * @param aiService Address of AI service
     */
    function grantAIServiceRole(address aiService) external onlyRole(ADMIN_ROLE) {
        grantRole(AI_SERVICE_ROLE, aiService);
    }

    /**
     * @notice Grant moderator role
     * @param moderator Address of moderator
     */
    function grantModeratorRole(address moderator) external onlyRole(ADMIN_ROLE) {
        grantRole(MODERATOR_ROLE, moderator);
    }
}

contracts/core/FeedbackContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./StudentRegistryContract.sol";
import "./AIModerationContract.sol";
import "../privacy/PrivacyContract.sol";

/**
 * @title FeedbackContract
 * @notice Manages feedback submission with AI moderation integration
 * @dev Stores feedback on-chain with IPFS content hashes
 */
contract FeedbackContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant MODERATOR_ROLE = keccak256("MODERATOR_ROLE");

    StudentRegistryContract public studentRegistry;
    AIModerationContract public aiModeration;
    PrivacyContract public privacyContract;

    enum FeedbackCategory {
        General,
        Infrastructure,
        Faculty,
        Administration,
        Food,
        Technology,
        Safety,
        Other
    }

    enum FeedbackStatus {
        Pending,
        Approved,
        Rejected,
        Implemented,
        UnderReview
    }

    struct Feedback {
        uint256 id;
        address author;
        FeedbackCategory category;
        bytes32 contentHash; // IPFS hash
        bytes32 imageHash;   // Optional image IPFS hash
        uint8 aiQualityScore;
        FeedbackStatus status;
        uint256 timestamp;
        bool isAnonymous;
        bool hasImage;
        uint256 upvotes;
        uint256 downvotes;
        bool isImplemented;
    }

    // Mappings
    mapping(uint256 => Feedback) public feedbacks;
    mapping(address => uint256[]) public userFeedbacks;
    mapping(FeedbackCategory => uint256[]) public categoryFeedbacks;
    mapping(uint256 => mapping(address => bool)) public hasVoted;
    mapping(uint256 => mapping(address => bool)) public hasUpvoted;
    
    uint256 public feedbackCounter;
    uint256 public totalFeedbacks;
    uint256 public approvedFeedbacks;
    uint256 public implementedFeedbacks;

    // Events
    event FeedbackSubmitted(
        uint256 indexed feedbackId,
        address indexed author,
        FeedbackCategory category,
        bool isAnonymous,
        uint256 timestamp
    );
    event FeedbackApproved(uint256 indexed feedbackId, uint256 timestamp);
    event FeedbackRejected(uint256 indexed feedbackId, string reason, uint256 timestamp);
    event FeedbackImplemented(uint256 indexed feedbackId, uint256 timestamp);
    event FeedbackVoted(uint256 indexed feedbackId, address indexed voter, bool isUpvote);
    event FeedbackStatusUpdated(uint256 indexed feedbackId, FeedbackStatus newStatus);

    constructor(
        address _studentRegistry,
        address _aiModeration,
        address _privacyContract
    ) {
        require(_studentRegistry != address(0), "Invalid student registry");
        require(_aiModeration != address(0), "Invalid AI moderation");
        require(_privacyContract != address(0), "Invalid privacy contract");

        studentRegistry = StudentRegistryContract(_studentRegistry);
        aiModeration = AIModerationContract(_aiModeration);
        privacyContract = PrivacyContract(_privacyContract);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    /**
     * @notice Submit feedback
     * @param category Feedback category
     * @param contentHash IPFS hash of feedback content
     * @param imageHash IPFS hash of image (optional)
     * @param aiQualityScore AI-determined quality score
     * @param isAnonymous Whether to submit anonymously
     * @return feedbackId ID of the created feedback
     */
    function submitFeedback(
        FeedbackCategory category,
        bytes32 contentHash,
        bytes32 imageHash,
        uint8 aiQualityScore,
        bool isAnonymous
    ) external nonReentrant returns (uint256) {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        require(contentHash != bytes32(0), "Invalid content hash");
        require(aiQualityScore <= 100, "Invalid quality score");

        // Check AI moderation result
        uint256 moderationId = feedbackCounter;
        AIModerationContract.ModerationResult memory modResult = 
            aiModeration.getModerationResult(moderationId);
        
        require(
            modResult.decision == AIModerationContract.ModerationDecision.Approved ||
            modResult.decision == AIModerationContract.ModerationDecision.Pending,
            "Content rejected by AI moderation"
        );

        feedbackCounter++;
        uint256 feedbackId = feedbackCounter;

        feedbacks[feedbackId] = Feedback({
            id: feedbackId,
            author: msg.sender,
            category: category,
            contentHash: contentHash,
            imageHash: imageHash,
            aiQualityScore: aiQualityScore,
            status: FeedbackStatus.Pending,
            timestamp: block.timestamp,
            isAnonymous: isAnonymous,
            hasImage: imageHash != bytes32(0),
            upvotes: 0,
            downvotes: 0,
            isImplemented: false
        });

        userFeedbacks[msg.sender].push(feedbackId);
        categoryFeedbacks[category].push(feedbackId);
        totalFeedbacks++;

        // If anonymous, mark content as anonymized
        if (isAnonymous) {
            privacyContract.anonymizeContent(feedbackId);
        }

        emit FeedbackSubmitted(feedbackId, msg.sender, category, isAnonymous, block.timestamp);

        return feedbackId;
    }

    /**
     * @notice Approve feedback (moderator only)
     * @param feedbackId ID of the feedback
     */
    function approveFeedback(uint256 feedbackId) 
        external 
        onlyRole(MODERATOR_ROLE) 
    {
        require(feedbacks[feedbackId].id != 0, "Feedback not found");
        require(feedbacks[feedbackId].status == FeedbackStatus.Pending, 
                "Feedback not pending");

        feedbacks[feedbackId].status = FeedbackStatus.Approved;
        approvedFeedbacks++;

        emit FeedbackApproved(feedbackId, block.timestamp);
    }

    /**
     * @notice Reject feedback (moderator only)
     * @param feedbackId ID of the feedback
     * @param reason Reason for rejection
     */
    function rejectFeedback(uint256 feedbackId, string memory reason) 
        external 
        onlyRole(MODERATOR_ROLE) 
    {
        require(feedbacks[feedbackId].id != 0, "Feedback not found");
        require(feedbacks[feedbackId].status == FeedbackStatus.Pending, 
                "Feedback not pending");
        require(bytes(reason).length > 0, "Reason required");

        feedbacks[feedbackId].status = FeedbackStatus.Rejected;

        emit FeedbackRejected(feedbackId, reason, block.timestamp);
    }

    /**
     * @notice Mark feedback as implemented
     * @param feedbackId ID of the feedback
     */
    function markAsImplemented(uint256 feedbackId) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        require(feedbacks[feedbackId].id != 0, "Feedback not found");
        require(feedbacks[feedbackId].status == FeedbackStatus.Approved, 
                "Feedback not approved");
        require(!feedbacks[feedbackId].isImplemented, "Already implemented");

        feedbacks[feedbackId].status = FeedbackStatus.Implemented;
        feedbacks[feedbackId].isImplemented = true;
        implementedFeedbacks++;

        emit FeedbackImplemented(feedbackId, block.timestamp);
    }

    /**
     * @notice Vote on feedback
     * @param feedbackId ID of the feedback
     * @param isUpvote True for upvote, false for downvote
     */
    function voteFeedback(uint256 feedbackId, bool isUpvote) external {
        require(feedbacks[feedbackId].id != 0, "Feedback not found");
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        require(!hasVoted[feedbackId][msg.sender], "Already voted");
        require(feedbacks[feedbackId].status == FeedbackStatus.Approved, 
                "Feedback not approved");

        hasVoted[feedbackId][msg.sender] = true;
        hasUpvoted[feedbackId][msg.sender] = isUpvote;

        if (isUpvote) {
            feedbacks[feedbackId].upvotes++;
        } else {
            feedbacks[feedbackId].downvotes++;
        }

        emit FeedbackVoted(feedbackId, msg.sender, isUpvote);
    }

    /**
     * @notice Get feedback by ID
     * @param feedbackId ID of the feedback
     * @return Feedback struct
     */
    function getFeedback(uint256 feedbackId) 
        external 
        view 
        returns (Feedback memory) 
    {
        return feedbacks[feedbackId];
    }

    /**
     * @notice Get user's feedbacks
     * @param user Address of the user
     * @return Array of feedback IDs
     */
    function getUserFeedbacks(address user) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return userFeedbacks[user];
    }

    /**
     * @notice Get feedbacks by category
     * @param category Feedback category
     * @return Array of feedback IDs
     */
    function getFeedbacksByCategory(FeedbackCategory category) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return categoryFeedbacks[category];
    }

    /**
     * @notice Get feedback statistics
     * @return total Total feedbacks
     * @return approved Approved feedbacks
     * @return implemented Implemented feedbacks
     */
    function getStatistics() 
        external 
        view 
        returns (uint256 total, uint256 approved, uint256 implemented) 
    {
        return (totalFeedbacks, approvedFeedbacks, implementedFeedbacks);
    }

    /**
     * @notice Update feedback status
     * @param feedbackId ID of the feedback
     * @param newStatus New status
     */
    function updateStatus(uint256 feedbackId, FeedbackStatus newStatus) 
        external 
        onlyRole(MODERATOR_ROLE) 
    {
        require(feedbacks[feedbackId].id != 0, "Feedback not found");
        
        feedbacks[feedbackId].status = newStatus;
        
        emit FeedbackStatusUpdated(feedbackId, newStatus);
    }

    /**
     * @notice Grant moderator role
     * @param moderator Address to grant role to
     */
    function grantModeratorRole(address moderator) external onlyRole(ADMIN_ROLE) {
        grantRole(MODERATOR_ROLE, moderator);
    }
}

contracts/core/PointEconomyContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./StudentRegistryContract.sol";

/**
 * @title PointEconomyContract
 * @notice Manages dynamic point-based reward system with AI quality bonuses
 * @dev 1000 points = 1 INR = ~1 SHM
 */
contract PointEconomyContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant REWARD_MANAGER_ROLE = keccak256("REWARD_MANAGER_ROLE");

    StudentRegistryContract public studentRegistry;

    uint256 public constant POINTS_TO_INR_RATIO = 1000; // 1000 points = 1 INR
    uint256 public constant POINTS_TO_SHM_RATIO = 1000; // 1000 points = 1 SHM

    enum ActivityType {
        BasicFeedback,
        FacultyRating,
        InfrastructureReport,
        InfrastructureWithImage,
        AIEnhancementAccepted,
        PeerVerification,
        WeeklyConsistency,
        AITrainingContribution
    }

    struct PointTransaction {
        address user;
        ActivityType activity;
        uint256 basePoints;
        uint256 qualityBonus;
        uint256 totalPoints;
        uint256 timestamp;
        string description;
    }

    struct UserPointsData {
        uint256 totalPoints;
        uint256 lifetimePoints;
        uint256 redeemedPoints;
        uint256 lastActivityTime;
        uint256 consecutiveDays;
        uint256 transactionCount;
    }

    // Base points for each activity
    mapping(ActivityType => uint256) public basePoints;
    mapping(ActivityType => uint256) public maxQualityBonus;

    // User data
    mapping(address => UserPointsData) public userPoints;
    mapping(address => PointTransaction[]) public userTransactions;
    mapping(address => mapping(uint256 => bool)) public dailyActivity; // user => day => hasActivity

    uint256 public totalPointsIssued;
    uint256 public totalPointsRedeemed;
    uint256 public totalTransactions;

    // Events
    event PointsAwarded(
        address indexed user,
        ActivityType activity,
        uint256 basePoints,
        uint256 qualityBonus,
        uint256 totalPoints,
        uint256 timestamp
    );
    event PointsRedeemed(address indexed user, uint256 points, uint256 shmAmount);
    event PointsTransferred(address indexed from, address indexed to, uint256 points);
    event StreakBonusAwarded(address indexed user, uint256 consecutiveDays, uint256 bonusPoints);
    event BasePointsUpdated(ActivityType activity, uint256 newBasePoints);

    constructor(address _studentRegistry) {
        require(_studentRegistry != address(0), "Invalid student registry");
        
        studentRegistry = StudentRegistryContract(_studentRegistry);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(REWARD_MANAGER_ROLE, msg.sender);

        // Initialize base points
        basePoints[ActivityType.BasicFeedback] = 10;
        basePoints[ActivityType.FacultyRating] = 25;
        basePoints[ActivityType.InfrastructureReport] = 30;
        basePoints[ActivityType.InfrastructureWithImage] = 50;
        basePoints[ActivityType.AIEnhancementAccepted] = 20;
        basePoints[ActivityType.PeerVerification] = 15;
        basePoints[ActivityType.WeeklyConsistency] = 100;
        basePoints[ActivityType.AITrainingContribution] = 50;

        // Initialize max quality bonuses
        maxQualityBonus[ActivityType.BasicFeedback] = 15;
        maxQualityBonus[ActivityType.FacultyRating] = 25;
        maxQualityBonus[ActivityType.InfrastructureReport] = 20;
        maxQualityBonus[ActivityType.InfrastructureWithImage] = 30;
        maxQualityBonus[ActivityType.AIEnhancementAccepted] = 0;
        maxQualityBonus[ActivityType.PeerVerification] = 10;
        maxQualityBonus[ActivityType.WeeklyConsistency] = 50;
        maxQualityBonus[ActivityType.AITrainingContribution] = 0;
    }

    /**
     * @notice Award points to user
     * @param user Address of the user
     * @param activity Type of activity
     * @param aiQualityScore AI quality score (0-100)
     * @param description Description of the activity
     */
    function awardPoints(
        address user,
        ActivityType activity,
        uint8 aiQualityScore,
        string memory description
    ) external onlyRole(REWARD_MANAGER_ROLE) {
        require(studentRegistry.isVerifiedStudent(user), "Not verified student");
        require(aiQualityScore <= 100, "Invalid quality score");

        uint256 base = basePoints[activity];
        uint256 bonus = calculateQualityBonus(activity, aiQualityScore);
        uint256 total = base + bonus;

        // Update user points
        userPoints[user].totalPoints += total;
        userPoints[user].lifetimePoints += total;
        userPoints[user].lastActivityTime = block.timestamp;
        userPoints[user].transactionCount++;

        // Record transaction
        userTransactions[user].push(PointTransaction({
            user: user,
            activity: activity,
            basePoints: base,
            qualityBonus: bonus,
            totalPoints: total,
            timestamp: block.timestamp,
            description: description
        }));

        // Update daily activity
        uint256 today = block.timestamp / 1 days;
        if (!dailyActivity[user][today]) {
            dailyActivity[user][today] = true;
            _updateStreak(user, today);
        }

        totalPointsIssued += total;
        totalTransactions++;

        emit PointsAwarded(user, activity, base, bonus, total, block.timestamp);
    }

    /**
     * @notice Calculate quality bonus based on AI score
     * @param activity Type of activity
     * @param aiQualityScore AI quality score (0-100)
     * @return Bonus points
     */
    function calculateQualityBonus(ActivityType activity, uint8 aiQualityScore) 
        public 
        view 
        returns (uint256) 
    {
        uint256 maxBonus = maxQualityBonus[activity];
        if (maxBonus == 0) return 0;

        // Linear scaling: higher quality = more bonus
        return (maxBonus * aiQualityScore) / 100;
    }

    /**
     * @notice Update user's consecutive days streak
     * @param user Address of the user
     * @param today Current day number
     */
    function _updateStreak(address user, uint256 today) internal {
        uint256 yesterday = today - 1;
        
        if (dailyActivity[user][yesterday]) {
            // Streak continues
            userPoints[user].consecutiveDays++;
            
            // Award streak bonus every 7 days
            if (userPoints[user].consecutiveDays % 7 == 0) {
                uint256 streakBonus = 50 * (userPoints[user].consecutiveDays / 7);
                userPoints[user].totalPoints += streakBonus;
                userPoints[user].lifetimePoints += streakBonus;
                
                emit StreakBonusAwarded(user, userPoints[user].consecutiveDays, streakBonus);
            }
        } else {
            // Streak broken, reset
            userPoints[user].consecutiveDays = 1;
        }
    }

    /**
     * @notice Redeem points for SHM
     * @param points Amount of points to redeem
     */
    function redeemPoints(uint256 points) external nonReentrant {
        require(userPoints[msg.sender].totalPoints >= points, "Insufficient points");
        require(points >= POINTS_TO_SHM_RATIO, "Minimum 1000 points required");
        require(points % POINTS_TO_SHM_RATIO == 0, "Points must be multiple of 1000");

        uint256 shmAmount = (points * 1 ether) / POINTS_TO_SHM_RATIO;
        require(address(this).balance >= shmAmount, "Insufficient contract balance");

        userPoints[msg.sender].totalPoints -= points;
        userPoints[msg.sender].redeemedPoints += points;
        totalPointsRedeemed += points;

        (bool success, ) = msg.sender.call{value: shmAmount}("");
        require(success, "Transfer failed");

        emit PointsRedeemed(msg.sender, points, shmAmount);
    }

    /**
     * @notice Transfer points to another user
     * @param to Recipient address
     * @param points Amount of points
     */
    function transferPoints(address to, uint256 points) external {
        require(studentRegistry.isVerifiedStudent(to), "Recipient not verified");
        require(userPoints[msg.sender].totalPoints >= points, "Insufficient points");
        require(points > 0, "Invalid amount");

        userPoints[msg.sender].totalPoints -= points;
        userPoints[to].totalPoints += points;

        emit PointsTransferred(msg.sender, to, points);
    }

    /**
     * @notice Get user's point balance
     * @param user Address of the user
     * @return Total points
     */
    function getPointBalance(address user) external view returns (uint256) {
        return userPoints[user].totalPoints;
    }

    /**
     * @notice Get user's points data
     * @param user Address of the user
     * @return User points data struct
     */
    function getUserPointsData(address user) 
        external 
        view 
        returns (UserPointsData memory) 
    {
        return userPoints[user];
    }

    /**
     * @notice Get user's transaction history
     * @param user Address of the user
     * @return Array of transactions
     */
    function getUserTransactions(address user) 
        external 
        view 
        returns (PointTransaction[] memory) 
    {
        return userTransactions[user];
    }

    /**
     * @notice Convert points to INR value
     * @param points Amount of points
     * @return INR value (in wei, 18 decimals)
     */
    function pointsToINR(uint256 points) external pure returns (uint256) {
        return (points * 1 ether) / POINTS_TO_INR_RATIO;
    }

    /**
     * @notice Convert points to SHM value
     * @param points Amount of points
     * @return SHM value (in wei)
     */
    function pointsToSHM(uint256 points) external pure returns (uint256) {
        return (points * 1 ether) / POINTS_TO_SHM_RATIO;
    }

    /**
     * @notice Update base points for activity
     * @param activity Activity type
     * @param newBasePoints New base points value
     */
    function updateBasePoints(ActivityType activity, uint256 newBasePoints) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        basePoints[activity] = newBasePoints;
        emit BasePointsUpdated(activity, newBasePoints);
    }

    /**
     * @notice Update max quality bonus for activity
     * @param activity Activity type
     * @param newMaxBonus New max bonus value
     */
    function updateMaxQualityBonus(ActivityType activity, uint256 newMaxBonus) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        maxQualityBonus[activity] = newMaxBonus;
    }

    /**
     * @notice Get global statistics
     * @return issued Total points issued
     * @return redeemed Total points redeemed
     * @return transactions Total transactions
     */
    function getGlobalStats() 
        external 
        view 
        returns (uint256 issued, uint256 redeemed, uint256 transactions) 
    {
        return (totalPointsIssued, totalPointsRedeemed, totalTransactions);
    }

    /**
     * @notice Fund contract with SHM for redemptions
     */
    function fundContract() external payable onlyRole(ADMIN_ROLE) {
        require(msg.value > 0, "Must send SHM");
    }

    /**
     * @notice Get contract balance
     * @return Balance in wei
     */
    function getContractBalance() external view returns (uint256) {
        return address(this).balance;
    }

    /**
     * @notice Grant reward manager role
     * @param manager Address to grant role to
     */
    function grantRewardManagerRole(address manager) external onlyRole(ADMIN_ROLE) {
        grantRole(REWARD_MANAGER_ROLE, manager);
    }

    receive() external payable {}
}

contracts/core/RatingContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./StudentRegistryContract.sol";
import "./AIModerationContract.sol";

/**
 * @title RatingContract
 * @notice Manages multi-dimensional ratings for faculty and infrastructure
 * @dev Supports 1-10 scale ratings with AI validation
 */
contract RatingContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant MODERATOR_ROLE = keccak256("MODERATOR_ROLE");

    StudentRegistryContract public studentRegistry;
    AIModerationContract public aiModeration;

    enum RatingType {
        Faculty,
        Infrastructure,
        FoodService,
        Administration,
        Technology,
        Safety
    }

    // Faculty rating dimensions (1-10 scale)
    struct FacultyRating {
        uint256 id;
        address rater;
        address faculty;
        uint8 teachingEffectiveness;
        uint8 accessibilitySupport;
        uint8 innovationAdaptability;
        uint8 assessmentFairness;
        uint8 professionalDevelopment;
        bytes32 commentHash; // IPFS hash
        uint256 timestamp;
        bool isAnonymous;
        bool isVerified;
    }

    // Infrastructure rating
    struct InfrastructureRating {
        uint256 id;
        address rater;
        string location;
        uint8 physicalCondition;
        uint8 technologySystems;
        uint8 learningEnvironment;
        uint8 recreationalFacilities;
        bytes32 commentHash;
        bytes32 imageHash;
        uint256 timestamp;
        bool isAnonymous;
        bool isVerified;
    }

    // Service rating
    struct ServiceRating {
        uint256 id;
        address rater;
        RatingType serviceType;
        uint8 quality;
        uint8 efficiency;
        uint8 responsiveness;
        uint8 satisfaction;
        bytes32 commentHash;
        uint256 timestamp;
        bool isAnonymous;
    }

    // Aggregate ratings
    struct FacultyAggregate {
        uint256 totalRatings;
        uint256 sumTeachingEffectiveness;
        uint256 sumAccessibilitySupport;
        uint256 sumInnovationAdaptability;
        uint256 sumAssessmentFairness;
        uint256 sumProfessionalDevelopment;
        uint256 lastUpdated;
    }

    // Mappings
    mapping(uint256 => FacultyRating) public facultyRatings;
    mapping(uint256 => InfrastructureRating) public infrastructureRatings;
    mapping(uint256 => ServiceRating) public serviceRatings;
    
    mapping(address => FacultyAggregate) public facultyAggregates;
    mapping(address => uint256[]) public facultyRatingIds;
    mapping(string => uint256[]) public locationRatingIds;
    mapping(address => mapping(address => bool)) public hasRatedFaculty;
    
    uint256 public facultyRatingCounter;
    uint256 public infrastructureRatingCounter;
    uint256 public serviceRatingCounter;

    // Events
    event FacultyRated(
        uint256 indexed ratingId,
        address indexed rater,
        address indexed faculty,
        uint8[5] dimensions,
        uint256 timestamp
    );
    event InfrastructureRated(
        uint256 indexed ratingId,
        address indexed rater,
        string location,
        uint256 timestamp
    );
    event ServiceRated(
        uint256 indexed ratingId,
        address indexed rater,
        RatingType serviceType,
        uint256 timestamp
    );
    event RatingVerified(uint256 indexed ratingId, RatingType ratingType);

    constructor(
        address _studentRegistry,
        address _aiModeration
    ) {
        require(_studentRegistry != address(0), "Invalid student registry");
        require(_aiModeration != address(0), "Invalid AI moderation");

        studentRegistry = StudentRegistryContract(_studentRegistry);
        aiModeration = AIModerationContract(_aiModeration);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    /**
     * @notice Submit faculty rating
     * @param faculty Address of faculty member
     * @param dimensions Array of 5 ratings (1-10 scale)
     * @param commentHash IPFS hash of comment
     * @param isAnonymous Whether to submit anonymously
     * @return ratingId ID of the created rating
     */
    function submitFacultyRating(
        address faculty,
        uint8[5] memory dimensions,
        bytes32 commentHash,
        bool isAnonymous
    ) external nonReentrant returns (uint256) {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        require(studentRegistry.isFaculty(faculty), "Not a faculty member");
        require(!hasRatedFaculty[msg.sender][faculty], "Already rated this faculty");
        
        // Validate dimensions (1-10 scale)
        for (uint i = 0; i < 5; i++) {
            require(dimensions[i] >= 1 && dimensions[i] <= 10, "Invalid rating value");
        }

        facultyRatingCounter++;
        uint256 ratingId = facultyRatingCounter;

        facultyRatings[ratingId] = FacultyRating({
            id: ratingId,
            rater: msg.sender,
            faculty: faculty,
            teachingEffectiveness: dimensions[0],
            accessibilitySupport: dimensions[1],
            innovationAdaptability: dimensions[2],
            assessmentFairness: dimensions[3],
            professionalDevelopment: dimensions[4],
            commentHash: commentHash,
            timestamp: block.timestamp,
            isAnonymous: isAnonymous,
            isVerified: false
        });

        facultyRatingIds[faculty].push(ratingId);
        hasRatedFaculty[msg.sender][faculty] = true;

        // Update aggregate
        _updateFacultyAggregate(faculty, dimensions);

        emit FacultyRated(ratingId, msg.sender, faculty, dimensions, block.timestamp);

        return ratingId;
    }

    /**
     * @notice Update faculty aggregate ratings
     */
    function _updateFacultyAggregate(address faculty, uint8[5] memory dimensions) internal {
        FacultyAggregate storage aggregate = facultyAggregates[faculty];
        
        aggregate.totalRatings++;
        aggregate.sumTeachingEffectiveness += dimensions[0];
        aggregate.sumAccessibilitySupport += dimensions[1];
        aggregate.sumInnovationAdaptability += dimensions[2];
        aggregate.sumAssessmentFairness += dimensions[3];
        aggregate.sumProfessionalDevelopment += dimensions[4];
        aggregate.lastUpdated = block.timestamp;
    }

    /**
     * @notice Submit infrastructure rating
     * @param location Location identifier
     * @param dimensions Array of 4 ratings (1-10 scale)
     * @param commentHash IPFS hash of comment
     * @param imageHash IPFS hash of image (optional)
     * @param isAnonymous Whether to submit anonymously
     * @return ratingId ID of the created rating
     */
    function submitInfrastructureRating(
        string memory location,
        uint8[4] memory dimensions,
        bytes32 commentHash,
        bytes32 imageHash,
        bool isAnonymous
    ) external nonReentrant returns (uint256) {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        require(bytes(location).length > 0, "Location required");
        
        // Validate dimensions (1-10 scale)
        for (uint i = 0; i < 4; i++) {
            require(dimensions[i] >= 1 && dimensions[i] <= 10, "Invalid rating value");
        }

        infrastructureRatingCounter++;
        uint256 ratingId = infrastructureRatingCounter;

        infrastructureRatings[ratingId] = InfrastructureRating({
            id: ratingId,
            rater: msg.sender,
            location: location,
            physicalCondition: dimensions[0],
            technologySystems: dimensions[1],
            learningEnvironment: dimensions[2],
            recreationalFacilities: dimensions[3],
            commentHash: commentHash,
            imageHash: imageHash,
            timestamp: block.timestamp,
            isAnonymous: isAnonymous,
            isVerified: false
        });

        locationRatingIds[location].push(ratingId);

        emit InfrastructureRated(ratingId, msg.sender, location, block.timestamp);

        return ratingId;
    }

    /**
     * @notice Submit service rating
     * @param serviceType Type of service
     * @param dimensions Array of 4 ratings (1-10 scale)
     * @param commentHash IPFS hash of comment
     * @param isAnonymous Whether to submit anonymously
     * @return ratingId ID of the created rating
     */
    function submitServiceRating(
        RatingType serviceType,
        uint8[4] memory dimensions,
        bytes32 commentHash,
        bool isAnonymous
    ) external nonReentrant returns (uint256) {
        require(studentRegistry.isVerifiedStudent(msg.sender), "Not verified student");
        
        // Validate dimensions (1-10 scale)
        for (uint i = 0; i < 4; i++) {
            require(dimensions[i] >= 1 && dimensions[i] <= 10, "Invalid rating value");
        }

        serviceRatingCounter++;
        uint256 ratingId = serviceRatingCounter;

        serviceRatings[ratingId] = ServiceRating({
            id: ratingId,
            rater: msg.sender,
            serviceType: serviceType,
            quality: dimensions[0],
            efficiency: dimensions[1],
            responsiveness: dimensions[2],
            satisfaction: dimensions[3],
            commentHash: commentHash,
            timestamp: block.timestamp,
            isAnonymous: isAnonymous
        });

        emit ServiceRated(ratingId, msg.sender, serviceType, block.timestamp);

        return ratingId;
    }

    /**
     * @notice Get average faculty ratings
     * @param faculty Address of faculty member
     * @return averages Array of 5 average ratings
     */
    function getAverageRating(address faculty) 
        external 
        view 
        returns (uint8[5] memory averages) 
    {
        FacultyAggregate memory aggregate = facultyAggregates[faculty];
        
        if (aggregate.totalRatings == 0) {
            return [0, 0, 0, 0, 0];
        }

        averages[0] = uint8(aggregate.sumTeachingEffectiveness / aggregate.totalRatings);
        averages[1] = uint8(aggregate.sumAccessibilitySupport / aggregate.totalRatings);
        averages[2] = uint8(aggregate.sumInnovationAdaptability / aggregate.totalRatings);
        averages[3] = uint8(aggregate.sumAssessmentFairness / aggregate.totalRatings);
        averages[4] = uint8(aggregate.sumProfessionalDevelopment / aggregate.totalRatings);

        return averages;
    }

    /**
     * @notice Get faculty rating history
     * @param faculty Address of faculty member
     * @return Array of rating IDs
     */
    function getRatingHistory(address faculty) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return facultyRatingIds[faculty];
    }

    /**
     * @notice Get infrastructure ratings for location
     * @param location Location identifier
     * @return Array of rating IDs
     */
    function getLocationRatings(string memory location) 
        external 
        view 
        returns (uint256[] memory) 
    {
        return locationRatingIds[location];
    }

    /**
     * @notice Get faculty rating details
     * @param ratingId ID of the rating
     * @return Faculty rating struct
     */
    function getFacultyRating(uint256 ratingId) 
        external 
        view 
        returns (FacultyRating memory) 
    {
        return facultyRatings[ratingId];
    }

    /**
     * @notice Get infrastructure rating details
     * @param ratingId ID of the rating
     * @return Infrastructure rating struct
     */
    function getInfrastructureRating(uint256 ratingId) 
        external 
        view 
        returns (InfrastructureRating memory) 
    {
        return infrastructureRatings[ratingId];
    }

    /**
     * @notice Get service rating details
     * @param ratingId ID of the rating
     * @return Service rating struct
     */
    function getServiceRating(uint256 ratingId) 
        external 
        view 
        returns (ServiceRating memory) 
    {
        return serviceRatings[ratingId];
    }

    /**
     * @notice Verify rating (moderator only)
     * @param ratingId ID of the rating
     * @param ratingType Type of rating
     */
    function verifyRating(uint256 ratingId, RatingType ratingType) 
        external 
        onlyRole(MODERATOR_ROLE) 
    {
        if (ratingType == RatingType.Faculty) {
            require(facultyRatings[ratingId].id != 0, "Rating not found");
            facultyRatings[ratingId].isVerified = true;
        } else if (ratingType == RatingType.Infrastructure) {
            require(infrastructureRatings[ratingId].id != 0, "Rating not found");
            infrastructureRatings[ratingId].isVerified = true;
        }

        emit RatingVerified(ratingId, ratingType);
    }

    /**
     * @notice Get rating statistics
     * @return faculty Total faculty ratings
     * @return infrastructure Total infrastructure ratings
     * @return service Total service ratings
     */
    function getStatistics() 
        external 
        view 
        returns (uint256 faculty, uint256 infrastructure, uint256 service) 
    {
        return (facultyRatingCounter, infrastructureRatingCounter, serviceRatingCounter);
    }

    /**
     * @notice Grant moderator role
     * @param moderator Address to grant role to
     */
    function grantModeratorRole(address moderator) external onlyRole(ADMIN_ROLE) {
        grantRole(MODERATOR_ROLE, moderator);
    }
}

contracts/core/StudentRegistryContract.s.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../privacy/PrivacyContract.sol";

/**
 * @title StudentRegistryContract
 * @notice Manages student registration and verification with privacy protection
 * @dev Integrates with PrivacyContract for anonymization features
 */
contract StudentRegistryContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant VERIFIER_ROLE = keccak256("VERIFIER_ROLE");

    uint256 public constant VERIFICATION_FEE = 60 ether; // 60 SHM in wei
    
    PrivacyContract public privacyContract;

    enum StudentStatus {
        NotRegistered,
        Pending,
        Verified,
        Rejected,
        Suspended
    }

    enum UserRole {
        Student,
        Faculty,
        Admin
    }

    struct StudentProfile {
        address studentAddress;
        bytes32 hashedIdentity; // Hash of student ID/documents
        StudentStatus status;
        UserRole role;
        uint256 registrationTime;
        uint256 verificationTime;
        string rejectionReason;
        bool isActive;
    }

    // Mappings
    mapping(address => StudentProfile) public students;
    mapping(bytes32 => address) public identityToAddress;
    mapping(address => uint256) public studentPoints;
    
    uint256 public totalStudents;
    uint256 public verifiedStudents;
    uint256 public pendingVerifications;

    // Events
    event StudentRegistered(
        address indexed student,
        bytes32 hashedIdentity,
        uint256 fee,
        uint256 timestamp
    );
    event StudentVerified(address indexed student, uint256 timestamp);
    event StudentRejected(address indexed student, string reason, uint256 timestamp);
    event StudentSuspended(address indexed student, string reason, uint256 timestamp);
    event StudentReactivated(address indexed student, uint256 timestamp);
    event VerificationFeeCollected(address indexed student, uint256 amount);
    event FeeWithdrawn(address indexed admin, uint256 amount);
    event RoleAssigned(address indexed user, UserRole role);

    constructor(address _privacyContract) {
        require(_privacyContract != address(0), "Invalid privacy contract");
        
        privacyContract = PrivacyContract(_privacyContract);
        
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(VERIFIER_ROLE, msg.sender);
    }

    /**
     * @notice Register as a student with verification fee
     * @param hashedIdentity Hashed student identity (privacy-preserving)
     */
    function registerStudent(bytes32 hashedIdentity) 
        external 
        payable 
        nonReentrant 
    {
        require(msg.value == VERIFICATION_FEE, "Incorrect verification fee");
        require(students[msg.sender].status == StudentStatus.NotRegistered, 
                "Already registered");
        require(identityToAddress[hashedIdentity] == address(0), 
                "Identity already registered");
        require(hashedIdentity != bytes32(0), "Invalid identity hash");

        students[msg.sender] = StudentProfile({
            studentAddress: msg.sender,
            hashedIdentity: hashedIdentity,
            status: StudentStatus.Pending,
            role: UserRole.Student,
            registrationTime: block.timestamp,
            verificationTime: 0,
            rejectionReason: "",
            isActive: true
        });

        identityToAddress[hashedIdentity] = msg.sender;
        totalStudents++;
        pendingVerifications++;

        emit StudentRegistered(msg.sender, hashedIdentity, msg.value, block.timestamp);
        emit VerificationFeeCollected(msg.sender, msg.value);
    }

    /**
     * @notice Verify a student (admin/verifier only)
     * @param studentAddress Address of the student to verify
     */
    function verifyStudent(address studentAddress) 
        external 
        onlyRole(VERIFIER_ROLE) 
    {
        require(students[studentAddress].status == StudentStatus.Pending, 
                "Student not pending verification");

        students[studentAddress].status = StudentStatus.Verified;
        students[studentAddress].verificationTime = block.timestamp;
        
        verifiedStudents++;
        pendingVerifications--;

        emit StudentVerified(studentAddress, block.timestamp);
    }

    /**
     * @notice Reject a student registration
     * @param studentAddress Address of the student
     * @param reason Reason for rejection
     */
    function rejectStudent(address studentAddress, string memory reason) 
        external 
        onlyRole(VERIFIER_ROLE) 
    {
        require(students[studentAddress].status == StudentStatus.Pending, 
                "Student not pending verification");
        require(bytes(reason).length > 0, "Reason required");

        students[studentAddress].status = StudentStatus.Rejected;
        students[studentAddress].rejectionReason = reason;
        
        pendingVerifications--;

        emit StudentRejected(studentAddress, reason, block.timestamp);
    }

    /**
     * @notice Suspend a student
     * @param studentAddress Address of the student
     * @param reason Reason for suspension
     */
    function suspendStudent(address studentAddress, string memory reason) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        require(students[studentAddress].status == StudentStatus.Verified, 
                "Student not verified");
        require(bytes(reason).length > 0, "Reason required");

        students[studentAddress].status = StudentStatus.Suspended;
        students[studentAddress].isActive = false;
        
        verifiedStudents--;

        emit StudentSuspended(studentAddress, reason, block.timestamp);
    }

    /**
     * @notice Reactivate a suspended student
     * @param studentAddress Address of the student
     */
    function reactivateStudent(address studentAddress) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        require(students[studentAddress].status == StudentStatus.Suspended, 
                "Student not suspended");

        students[studentAddress].status = StudentStatus.Verified;
        students[studentAddress].isActive = true;
        
        verifiedStudents++;

        emit StudentReactivated(studentAddress, block.timestamp);
    }

    /**
     * @notice Check if address is a verified student
     * @param studentAddress Address to check
     * @return True if verified student
     */
    function isVerifiedStudent(address studentAddress) external view returns (bool) {
        return students[studentAddress].status == StudentStatus.Verified &&
               students[studentAddress].isActive;
    }

    /**
     * @notice Get student status
     * @param studentAddress Address of the student
     * @return Current status
     */
    function getStudentStatus(address studentAddress) 
        external 
        view 
        returns (StudentStatus) 
    {
        return students[studentAddress].status;
    }

    /**
     * @notice Get student profile
     * @param studentAddress Address of the student
     * @return Student profile struct
     */
    function getStudentProfile(address studentAddress) 
        external 
        view 
        returns (StudentProfile memory) 
    {
        return students[studentAddress];
    }

    /**
     * @notice Assign role to user (faculty, admin)
     * @param userAddress Address of the user
     * @param role Role to assign
     */
    function assignRole(address userAddress, UserRole role) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        require(userAddress != address(0), "Invalid address");
        
        if (students[userAddress].studentAddress == address(0)) {
            // Create new profile for non-student users
            students[userAddress] = StudentProfile({
                studentAddress: userAddress,
                hashedIdentity: bytes32(0),
                status: StudentStatus.Verified,
                role: role,
                registrationTime: block.timestamp,
                verificationTime: block.timestamp,
                rejectionReason: "",
                isActive: true
            });
        } else {
            students[userAddress].role = role;
        }

        emit RoleAssigned(userAddress, role);
    }

    /**
     * @notice Get user role
     * @param userAddress Address of the user
     * @return User role
     */
    function getUserRole(address userAddress) external view returns (UserRole) {
        return students[userAddress].role;
    }

    /**
     * @notice Check if user is faculty
     * @param userAddress Address to check
     * @return True if faculty
     */
    function isFaculty(address userAddress) external view returns (bool) {
        return students[userAddress].role == UserRole.Faculty &&
               students[userAddress].isActive;
    }

    /**
     * @notice Check if user is admin
     * @param userAddress Address to check
     * @return True if admin
     */
    function isAdmin(address userAddress) external view returns (bool) {
        return students[userAddress].role == UserRole.Admin &&
               students[userAddress].isActive;
    }

    /**
     * @notice Withdraw collected fees (admin only)
     * @param amount Amount to withdraw
     */
    function withdrawFees(uint256 amount) 
        external 
        onlyRole(ADMIN_ROLE) 
        nonReentrant 
    {
        require(amount <= address(this).balance, "Insufficient balance");
        
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "Transfer failed");

        emit FeeWithdrawn(msg.sender, amount);
    }

    /**
     * @notice Get contract balance
     * @return Balance in wei
     */
    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }

    /**
     * @notice Get registration statistics
     * @return total Total registered students
     * @return verified Total verified students
     * @return pending Total pending verifications
     */
    function getStatistics() 
        external 
        view 
        returns (uint256 total, uint256 verified, uint256 pending) 
    {
        return (totalStudents, verifiedStudents, pendingVerifications);
    }

    /**
     * @notice Grant verifier role
     * @param verifier Address to grant role to
     */
    function grantVerifierRole(address verifier) external onlyRole(ADMIN_ROLE) {
        grantRole(VERIFIER_ROLE, verifier);
    }

    /**
     * @notice Revoke verifier role
     * @param verifier Address to revoke role from
     */
    function revokeVerifierRole(address verifier) external onlyRole(ADMIN_ROLE) {
        revokeRole(VERIFIER_ROLE, verifier);
    }
}

contracts/privacy/PrivacyContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title PrivacyContract
 * @notice Manages privacy-preserving features including anonymization and data protection
 * @dev Implements zero-knowledge verification and GDPR compliance mechanisms
 */
contract PrivacyContract is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant MODERATOR_ROLE = keccak256("MODERATOR_ROLE");

    // Privacy settings
    struct PrivacySettings {
        bool isAnonymous;
        bool allowDataCollection;
        uint256 dataRetentionPeriod; // in days
        uint256 lastUpdated;
    }

    // Data deletion request
    struct DeletionRequest {
        address requester;
        uint256 requestTime;
        bool processed;
        bool approved;
        string reason;
    }

    // Mappings
    mapping(address => PrivacySettings) public userPrivacySettings;
    mapping(address => DeletionRequest) public deletionRequests;
    mapping(bytes32 => bool) public verifiedProofs; // For zero-knowledge proofs
    mapping(uint256 => bool) public anonymizedContent; // Content ID => is anonymized

    // Events
    event PrivacySettingsUpdated(address indexed user, bool isAnonymous, uint256 timestamp);
    event DeletionRequested(address indexed user, uint256 timestamp);
    event DeletionProcessed(address indexed user, bool approved, uint256 timestamp);
    event ProofVerified(bytes32 indexed proofHash, bool valid, uint256 timestamp);
    event ContentAnonymized(uint256 indexed contentId, uint256 timestamp);
    event DataAccessLogged(address indexed accessor, address indexed subject, uint256 timestamp);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    /**
     * @notice Update user privacy settings
     * @param isAnonymous Whether user wants anonymous interactions
     * @param allowDataCollection Whether to allow data collection for analytics
     * @param retentionDays Data retention period in days
     */
    function updatePrivacySettings(
        bool isAnonymous,
        bool allowDataCollection,
        uint256 retentionDays
    ) external {
        require(retentionDays >= 30 && retentionDays <= 3650, "Invalid retention period");

        userPrivacySettings[msg.sender] = PrivacySettings({
            isAnonymous: isAnonymous,
            allowDataCollection: allowDataCollection,
            dataRetentionPeriod: retentionDays,
            lastUpdated: block.timestamp
        });

        emit PrivacySettingsUpdated(msg.sender, isAnonymous, block.timestamp);
    }

    /**
     * @notice Get user privacy settings
     * @param user Address of the user
     * @return Privacy settings struct
     */
    function getPrivacySettings(address user) external view returns (PrivacySettings memory) {
        return userPrivacySettings[user];
    }

    /**
     * @notice Check if user prefers anonymous interactions
     * @param user Address of the user
     * @return True if user wants anonymity
     */
    function isAnonymousUser(address user) external view returns (bool) {
        return userPrivacySettings[user].isAnonymous;
    }

    /**
     * @notice Request data deletion (GDPR right to be forgotten)
     * @param reason Reason for deletion request
     */
    function requestDataDeletion(string memory reason) external {
        require(deletionRequests[msg.sender].requestTime == 0 || 
                deletionRequests[msg.sender].processed, 
                "Pending deletion request exists");

        deletionRequests[msg.sender] = DeletionRequest({
            requester: msg.sender,
            requestTime: block.timestamp,
            processed: false,
            approved: false,
            reason: reason
        });

        emit DeletionRequested(msg.sender, block.timestamp);
    }

    /**
     * @notice Process data deletion request (admin only)
     * @param user Address of the user
     * @param approved Whether to approve the deletion
     */
    function processDeletionRequest(address user, bool approved) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        require(deletionRequests[user].requestTime > 0, "No deletion request found");
        require(!deletionRequests[user].processed, "Request already processed");

        deletionRequests[user].processed = true;
        deletionRequests[user].approved = approved;

        emit DeletionProcessed(user, approved, block.timestamp);
    }

    /**
     * @notice Verify zero-knowledge proof
     * @param proof The proof bytes
     * @param publicInput Public input for verification
     * @return True if proof is valid
     */
    function verifyZKProof(bytes memory proof, bytes32 publicInput) 
        external 
        returns (bool) 
    {
        // Simplified ZK proof verification
        // In production, integrate with actual ZK proof library (e.g., Groth16, PLONK)
        bytes32 proofHash = keccak256(abi.encodePacked(proof, publicInput));
        
        // For demo: proof is valid if it hasn't been used before
        bool isValid = !verifiedProofs[proofHash];
        
        if (isValid) {
            verifiedProofs[proofHash] = true;
            emit ProofVerified(proofHash, true, block.timestamp);
        }

        return isValid;
    }

    /**
     * @notice Mark content as anonymized
     * @param contentId ID of the content
     */
    function anonymizeContent(uint256 contentId) 
        external 
        onlyRole(MODERATOR_ROLE) 
    {
        require(!anonymizedContent[contentId], "Content already anonymized");
        
        anonymizedContent[contentId] = true;
        emit ContentAnonymized(contentId, block.timestamp);
    }

    /**
     * @notice Check if content is anonymized
     * @param contentId ID of the content
     * @return True if content is anonymized
     */
    function isContentAnonymized(uint256 contentId) external view returns (bool) {
        return anonymizedContent[contentId];
    }

    /**
     * @notice Log data access for audit trail
     * @param subject Address whose data is being accessed
     */
    function logDataAccess(address subject) external {
        emit DataAccessLogged(msg.sender, subject, block.timestamp);
    }

    /**
     * @notice Check if data retention period has expired
     * @param user Address of the user
     * @return True if data should be deleted
     */
    function shouldDeleteData(address user) external view returns (bool) {
        PrivacySettings memory settings = userPrivacySettings[user];
        if (settings.lastUpdated == 0) return false;
        
        uint256 retentionSeconds = settings.dataRetentionPeriod * 1 days;
        return block.timestamp > settings.lastUpdated + retentionSeconds;
    }

    /**
     * @notice Grant moderator role
     * @param moderator Address to grant role to
     */
    function grantModeratorRole(address moderator) external onlyRole(ADMIN_ROLE) {
        grantRole(MODERATOR_ROLE, moderator);
    }

    /**
     * @notice Revoke moderator role
     * @param moderator Address to revoke role from
     */
    function revokeModeratorRole(address moderator) external onlyRole(ADMIN_ROLE) {
        revokeRole(MODERATOR_ROLE, moderator);
    }
}

